public class ExecServiceImpl implements ExecService { private static final Log LOG = LogFactory . getLog ( ExecServiceImpl . class ) ; private static AppConfig appConf = Main . getAppConfigInstance ( ) ; private static volatile ExecServiceImpl theSingleton ; private static final Object WindowsProcessLaunchLock = new Object ( ) ; public static synchronized ExecServiceImpl getInstance ( ) { if ( theSingleton == null ) { theSingleton = new ExecServiceImpl ( ) ; } return theSingleton ; } private Semaphore avail ; private ExecServiceImpl ( ) { avail = new Semaphore ( appConf . getInt ( AppConfig . EXEC_MAX_PROCS_NAME , 16 ) ) ; } public ExecBean run ( String program , List < String > args , Map < String , String > env ) throws NotAuthorizedException , BusyException , ExecuteException , IOException { boolean aquired = false ; try { aquired = avail . tryAcquire ( ) ; if ( aquired ) { return runUnlimited ( program , args , env ) ; } else { throw new BusyException ( ) ; } } finally { if ( aquired ) { avail . release ( ) ; } } } public ExecBean runUnlimited ( String program , List < String > args , Map < String , String > env ) throws NotAuthorizedException , ExecuteException , IOException { try { return auxRun ( program , args , env ) ; } catch ( IOException e ) { File cwd = new java . io . File ( "." ) ; if ( cwd . canRead ( ) && cwd . canWrite ( ) ) throw e ; else throw new IOException ( "Invalid permissions on Templeton directory: " + cwd . getCanonicalPath ( ) ) ; } } private ExecBean auxRun ( String program , List < String > args , Map < String , String > env ) throws NotAuthorizedException , ExecuteException , IOException { DefaultExecutor executor = new DefaultExecutor ( ) ; executor . setExitValues ( null ) ; int nbytes = appConf . getInt ( AppConfig . EXEC_MAX_BYTES_NAME , - 1 ) ; ByteArrayOutputStream outStream = new MaxByteArrayOutputStream ( nbytes ) ; ByteArrayOutputStream errStream = new MaxByteArrayOutputStream ( nbytes ) ; executor . setStreamHandler ( new PumpStreamHandler ( outStream , errStream ) ) ; int timeout = appConf . getInt ( AppConfig . EXEC_TIMEOUT_NAME , 0 ) ; ExecuteWatchdog watchdog = new ExecuteWatchdog ( timeout ) ; executor . setWatchdog ( watchdog ) ; CommandLine cmd = makeCommandLine ( program , args ) ; LOG . info ( "Running: " + cmd ) ; ExecBean res = new ExecBean ( ) ; if ( Shell . WINDOWS ) { env = execEnv ( env ) ; String [ ] envVals = new String [ env . size ( ) ] ; int i = 0 ; for ( Entry < String , String > kv : env . entrySet ( ) ) { envVals [ i ++ ] = kv . getKey ( ) + "=" + kv . getValue ( ) ; LOG . info ( "Setting " + kv . getKey ( ) + "=" + kv . getValue ( ) ) ; } Process proc ; synchronized ( WindowsProcessLaunchLock ) { proc = Runtime . getRuntime ( ) . exec ( cmd . toStrings ( ) , envVals ) ; } StreamOutputWriter errorGobbler = new StreamOutputWriter ( proc . getErrorStream ( ) , "ERROR" , errStream ) ; StreamOutputWriter outputGobbler = new StreamOutputWriter ( proc . getInputStream ( ) , "OUTPUT" , outStream ) ; errorGobbler . start ( ) ; outputGobbler . start ( ) ; try { res . exitcode = proc . waitFor ( ) ; } catch ( InterruptedException e ) { throw new IOException ( e ) ; } errorGobbler . out . flush ( ) ; outputGobbler . out . flush ( ) ; } else { res . exitcode = executor . execute ( cmd , execEnv ( env ) ) ; } String enc = appConf . get ( AppConfig . EXEC_ENCODING_NAME ) ; res . stdout = outStream . toString ( enc ) ; res . stderr = errStream . toString ( enc ) ; try { watchdog . checkException ( ) ; } catch ( Exception ex ) { LOG . error ( "Command: " + cmd + " failed:" , ex ) ; } if ( watchdog . killedProcess ( ) ) { String msg = " was terminated due to timeout(" + timeout + "ms).  See " + AppConfig . EXEC_TIMEOUT_NAME + " property" ; LOG . warn ( "Command: " + cmd + msg ) ; res . stderr += " Command " + msg ; } return res ; } private CommandLine makeCommandLine ( String program , List < String > args ) throws NotAuthorizedException , IOException { String path = validateProgram ( program ) ; CommandLine cmd = new CommandLine ( path ) ; if ( args != null ) for ( String arg : args ) cmd . addArgument ( arg , false ) ; return cmd ; } public Map < String , String > execEnv ( Map < String , String > env ) { HashMap < String , String > res = new HashMap < String , String > ( ) ; for ( String key : appConf . getStrings ( AppConfig . EXEC_ENVS_NAME ) ) { String val = System . getenv ( key ) ; if ( val != null ) { res . put ( key , val ) ; } } if ( env != null ) res . putAll ( env ) ; for ( Map . Entry < String , String > envs : res . entrySet ( ) ) { LOG . info ( "Env " + envs . getKey ( ) + "=" + envs . getValue ( ) ) ; } return res ; } public String validateProgram ( String path ) throws NotAuthorizedException , IOException { File f = new File ( path ) ; if ( f . canExecute ( ) ) { return f . getCanonicalPath ( ) ; } else { throw new NotAuthorizedException ( "Unable to access program: " + path ) ; } } }